import { useState } from 'react';
import { motion } from 'framer-motion';
import { useChessGame } from './hooks/useChessGame';
import ChessBoard from './components/ChessBoard';
import GameInfo from './components/GameInfo';
import MoveHistory from './components/MoveHistory';
import CapturedPieces from './components/CapturedPieces';
import GameControls from './components/GameControls';
import PromotionModal from './components/PromotionModal';
import type { PieceType } from './types/chess.types';
import { Chess } from 'chess.js';

function App() {
  const [isBoardFlipped, setIsBoardFlipped] = useState(false);
  const [promotionModal, setPromotionModal] = useState<{
    isOpen: boolean;
    from: string;
    to: string;
  }>({
    isOpen: false,
    from: '',
    to: ''
  });

  const game = useChessGame();

  const handleSquareClick = (square: string) => {
    if (game.isGameOver()) return;

    // If we have a selected square and clicked on a valid move
    if (game.selectedSquare && game.validMoves.includes(square)) {
      const piece = game.getPieceAt(game.selectedSquare);

      // Check if it's a pawn promotion
      if (piece?.type === 'p') {
        const toRank = parseInt(square[1]);

        // White pawn reaching rank 8 or black pawn reaching rank 1
        if ((piece.color === 'w' && toRank === 8) || (piece.color === 'b' && toRank === 1)) {
          setPromotionModal({
            isOpen: true,
            from: game.selectedSquare,
            to: square
          });
          return;
        }
      }

      // Regular move
      game.makeMove(game.selectedSquare, square);
    } else {
      // Select a piece
      game.selectSquare(square);
    }
  };

  const handlePromotionSelect = (pieceType: PieceType) => {
    const { from, to } = promotionModal;
    game.makeMove(from, to, pieceType);
    setPromotionModal({ isOpen: false, from: '', to: '' });
  };

  const handleNewGame = () => {
    game.resetGame();
    setIsBoardFlipped(false);
  };

  const handleFlipBoard = () => {
    setIsBoardFlipped(!isBoardFlipped);
  };

  const handleCopyFEN = () => {
    const tempGame = new Chess();
    game.moveHistory.forEach(move => {
      tempGame.move({ from: move.from, to: move.to, promotion: move.promotion });
    });
    navigator.clipboard.writeText(tempGame.fen());
  };

  return (
    <div className="min-h-screen py-8 px-4">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <motion.div
          className="text-center mb-8"
          initial={{ y: -20, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          transition={{ duration: 0.5 }}
        >
          <h1 className="text-5xl font-bold bg-gradient-to-r from-amber-200 via-yellow-300 to-amber-200 bg-clip-text text-transparent mb-2">
            Chess Game
          </h1>
          <p className="text-gray-400">Play chess with a beautiful interface</p>
        </motion.div>

        <div className="grid lg:grid-cols-[1fr,350px] gap-6">
          {/* Main Board Section */}
          <div className="flex flex-col items-center">
            <GameInfo
              turn={game.turn}
              gameStatus={game.gameStatus}
              moveCount={game.moveHistory.length}
            />

            <ChessBoard
              board={game.board}
              selectedSquare={game.selectedSquare}
              validMoves={game.validMoves}
              lastMove={game.lastMove}
              onSquareClick={handleSquareClick}
              isFlipped={isBoardFlipped}
              isSquareInCheck={game.isSquareInCheck}
              size={Math.min(600, window.innerWidth - 32)}
            />
          </div>

          {/* Side Panel */}
          <div className="space-y-6">
            <MoveHistory moves={game.moveHistory} />
            <CapturedPieces
              white={game.capturedPieces.white}
              black={game.capturedPieces.black}
            />
            <GameControls
              onNewGame={handleNewGame}
              onUndo={game.undoMove}
              onFlipBoard={handleFlipBoard}
              onCopyFEN={handleCopyFEN}
              canUndo={game.moveHistory.length > 0}
              isGameOver={game.isGameOver()}
            />
          </div>
        </div>

        {/* Footer */}
        <motion.div
          className="text-center mt-8 text-gray-500 text-sm"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 0.5, delay: 0.5 }}
        >
          <p>Built with React, TypeScript, chess.js, and Framer Motion</p>
        </motion.div>
      </div>

      {/* Promotion Modal */}
      <PromotionModal
        isOpen={promotionModal.isOpen}
        color={game.turn}
        onSelect={handlePromotionSelect}
      />
    </div>
  );
}

export default App;

