import React from 'react';
import { motion } from 'framer-motion';
import type { Piece } from '../types/chess.types';
import { getPieceUnicode } from '../hooks/useChessGame';

interface CapturedPiecesProps {
  white: Piece[];
  black: Piece[];
}

const pieceOrder: Array<Piece['type']> = ['q', 'r', 'b', 'n', 'p'];

const CapturedPieces: React.FC<CapturedPiecesProps> = ({ white, black }) => {
  const sortPieces = (pieces: Piece[]): Piece[] => {
    return [...pieces].sort((a, b) => {
      return pieceOrder.indexOf(a.type) - pieceOrder.indexOf(b.type);
    });
  };

  const calculateAdvantage = (): string => {
    const pieceValues: Record<Piece['type'], number> = {
      p: 1,
      n: 3,
      b: 3,
      r: 5,
      q: 9,
      k: 0
    };

    const whiteValue = white.reduce((sum, piece) => sum + pieceValues[piece.type], 0);
    const blackValue = black.reduce((sum, piece) => sum + pieceValues[piece.type], 0);
    const diff = whiteValue - blackValue;

    if (diff > 0) return `+${diff} White`;
    if (diff < 0) return `${diff} Black`;
    return 'Equal';
  };

  return (
    <motion.div
      className="glass-panel rounded-xl p-4"
      initial={{ x: 20, opacity: 0 }}
      animate={{ x: 0, opacity: 1 }}
      transition={{ duration: 0.3, delay: 0.2 }}
    >
      <h3 className="text-lg font-semibold mb-3 text-gray-200">Captured Pieces</h3>

      <div className="space-y-3">
        {/* Captured by White (Black pieces) */}
        <div className="bg-gray-800/50 rounded-lg p-3">
          <div className="text-xs text-gray-400 mb-2">Captured by White</div>
          <div className="flex flex-wrap gap-1">
            {sortPieces(black).map((piece, index) => (
              <motion.span
                key={`black-${index}`}
                className="text-2xl"
                style={{
                  color: '#1a1a1a',
                  filter: 'drop-shadow(1px 1px 1px rgba(255,255,255,0.2))',
                  fontSize: '1.5rem'
                }}
                initial={{ scale: 0, rotate: -180 }}
                animate={{ scale: 1, rotate: 0 }}
                transition={{ duration: 0.3, delay: index * 0.02 }}
              >
                {getPieceUnicode(piece)}
              </motion.span>
            ))}
            {black.length === 0 && (
              <span className="text-gray-600 text-sm italic">None</span>
            )}
          </div>
        </div>

        {/* Captured by Black (White pieces) */}
        <div className="bg-gray-800/50 rounded-lg p-3">
          <div className="text-xs text-gray-400 mb-2">Captured by Black</div>
          <div className="flex flex-wrap gap-1">
            {sortPieces(white).map((piece, index) => (
              <motion.span
                key={`white-${index}`}
                className="text-2xl"
                style={{
                  color: '#f0f0f0',
                  filter: 'drop-shadow(1px 1px 1px rgba(0,0,0,0.5))',
                  fontSize: '1.5rem'
                }}
                initial={{ scale: 0, rotate: -180 }}
                animate={{ scale: 1, rotate: 0 }}
                transition={{ duration: 0.3, delay: index * 0.02 }}
              >
                {getPieceUnicode(piece)}
              </motion.span>
            ))}
            {white.length === 0 && (
              <span className="text-gray-600 text-sm italic">None</span>
            )}
          </div>
        </div>

        {/* Material advantage */}
        <div className="text-center pt-2 border-t border-gray-700/30">
          <div className="text-sm text-gray-400">Material Advantage</div>
          <motion.div
            className="text-lg font-semibold mt-1"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ duration: 0.5 }}
            style={{
              color: calculateAdvantage().includes('White')
                ? '#ffffff'
                : calculateAdvantage().includes('Black')
                ? '#9ca3af'
                : '#fbbf24'
            }}
          >
            {calculateAdvantage()}
          </motion.div>
        </div>
      </div>
    </motion.div>
  );
};

export default CapturedPieces;

