@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  body {
    @apply bg-gradient-to-br from-slate-900 via-slate-800 to-slate-900 text-white min-h-screen;
  }
}

@layer components {
  .chess-piece {
    filter: drop-shadow(2px 2px 2px rgba(0, 0, 0, 0.3));
    transition: transform 0.15s ease;
    user-select: none;
    cursor: grab;
  }

  .chess-piece:hover {
    transform: scale(1.05);
  }

  .chess-piece:active {
    cursor: grabbing;
  }

  .chess-square {
    transition: all 0.2s ease;
  }

  .chess-square.highlighted {
    box-shadow: inset 0 0 20px rgba(255, 215, 0, 0.8);
  }

  .chess-square.valid-move::after {
    content: '';
    position: absolute;
    width: 30%;
    height: 30%;
    background-color: rgba(0, 0, 0, 0.2);
    border-radius: 50%;
  }

  .chess-square.valid-capture::after {
    content: '';
    position: absolute;
    width: 80%;
    height: 80%;
    border: 4px solid rgba(0, 0, 0, 0.2);
    border-radius: 50%;
  }

  .chess-square.check {
    animation: pulse-red 1.5s infinite;
  }

  @keyframes pulse-red {
    0%, 100% {
      box-shadow: inset 0 0 20px rgba(239, 68, 68, 0.6);
    }
    50% {
      box-shadow: inset 0 0 30px rgba(239, 68, 68, 0.9);
    }
  }

  .chess-square.last-move {
    background-color: rgba(155, 199, 0, 0.4) !important;
  }

  .glass-panel {
    background: rgba(255, 255, 255, 0.05);
    backdrop-filter: blur(10px);
    border: 1px solid rgba(255, 255, 255, 0.1);
  }

  .btn-primary {
    @apply px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg font-medium transition-colors duration-200 shadow-lg hover:shadow-xl;
  }

  .btn-secondary {
    @apply px-4 py-2 bg-slate-700 hover:bg-slate-600 text-white rounded-lg font-medium transition-colors duration-200 shadow-lg hover:shadow-xl;
  }

  /* Scrollbar styling for move history */
  .custom-scrollbar::-webkit-scrollbar {
    width: 8px;
  }

  .custom-scrollbar::-webkit-scrollbar-track {
    background: rgba(255, 255, 255, 0.05);
    border-radius: 4px;
  }

  .custom-scrollbar::-webkit-scrollbar-thumb {
    background: rgba(255, 255, 255, 0.2);
    border-radius: 4px;
  }

  .custom-scrollbar::-webkit-scrollbar-thumb:hover {
    background: rgba(255, 255, 255, 0.3);
  }
}

