import React from 'react';
import { motion } from 'framer-motion';
import type { Piece } from '../types/chess.types';
import { getPieceUnicode } from '../hooks/useChessGame';

interface ChessPieceProps {
  piece: Piece;
  isSelected?: boolean;
  onClick?: () => void;
  size?: number;
}

export const ChessPiece: React.FC<ChessPieceProps> = ({
  piece,
  isSelected = false,
  onClick,
  size = 60
}) => {
  const pieceSymbol = getPieceUnicode(piece);

  return (
    <motion.div
      className={`chess-piece flex items-center justify-center text-${size}px cursor-pointer ${
        piece.color === 'w' ? 'text-white' : 'text-gray-900'
      }`}
      style={{
        fontSize: size * 0.85,
        width: size,
        height: size,
        filter: piece.color === 'w'
          ? 'drop-shadow(2px 2px 2px rgba(0,0,0,0.8))'
          : 'drop-shadow(2px 2px 2px rgba(255,255,255,0.3))',
        textShadow: piece.color === 'w'
          ? '1px 1px 2px rgba(0,0,0,0.8), -1px -1px 2px rgba(0,0,0,0.8), 1px -1px 2px rgba(0,0,0,0.8), -1px 1px 2px rgba(0,0,0,0.8)'
          : '1px 1px 2px rgba(255,255,255,0.3), -1px -1px 2px rgba(255,255,255,0.3), 1px -1px 2px rgba(255,255,255,0.3), -1px 1px 2px rgba(255,255,255,0.3)'
      }}
      onClick={onClick}
      initial={{ scale: 0 }}
      animate={{
        scale: isSelected ? 1.1 : 1,
        y: isSelected ? -4 : 0
      }}
      whileHover={{ scale: 1.05 }}
      whileTap={{ scale: 0.95 }}
      transition={{
        type: 'spring',
        stiffness: 300,
        damping: 20
      }}
    >
      {pieceSymbol}
    </motion.div>
  );
};

export default ChessPiece;

